@namespace Lumeo

<div class="@RootClasses" style="@RootStyle" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    /// <summary>Number of columns at the widest breakpoint. Values 1–6 get responsive Tailwind classes that collapse on mobile/tablet; other values fall back to an inline <c>grid-template-columns</c> with no responsive collapsing. Default <c>4</c>.</summary>
    [Parameter] public int Columns { get; set; } = 4;

    /// <summary>Gap between tiles. Default <see cref="BentoGap.Md"/>.</summary>
    [Parameter] public BentoGap Gap { get; set; } = BentoGap.Md;

    /// <summary>Additional CSS classes merged onto the grid's root element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>The grid's tiles, typically a sequence of <see cref="BentoTile"/> elements.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Unmatched attributes splatted onto the grid's root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string GapClass => Gap switch
    {
        BentoGap.Sm => "gap-3",
        BentoGap.Lg => "gap-6",
        _ => "gap-4"
    };

    // Pre-approved column counts use responsive Tailwind utilities so the grid
    // collapses gracefully on mobile (1 col), tablet (2 cols) and only expands
    // to the caller-configured count at the lg: breakpoint. Without this,
    // a Bento Columns="4" on a 375 px phone screen renders four tiny columns
    // and the embedded components become unreadable.
    private string ColumnsClass => Columns switch
    {
        1 => "grid-cols-1",
        2 => "grid-cols-1 sm:grid-cols-2",
        3 => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
        4 => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-4",
        5 => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-5",
        6 => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-6",
        _ => ""
    };

    private string RootStyle
    {
        get
        {
            // Non-standard column count — fall back to inline grid-template-columns
            // without responsive breakpoints. (Inline styles can't carry media queries.)
            if (string.IsNullOrEmpty(ColumnsClass))
            {
                // Clamp the lower bound: repeat(0, …) / repeat(-1, …) is invalid CSS and
                // collapses the grid to a single implicit column. A degenerate/empty bound
                // count (Columns <= 0) still yields a valid single-column template.
                var n = Math.Max(1, Columns);
                return $"grid-template-columns: repeat({n}, minmax(0, 1fr));";
            }
            return string.Empty;
        }
    }

    // `lg:auto-rows-fr` is what keeps mixed-RowSpan tiles aligned on desktop —
    // every row resolves to the same fr unit so a Span=2 RowSpan=2 tile is
    // exactly twice as tall as a single tile. On mobile we deliberately let
    // rows size to content (`auto-rows-auto`); otherwise a stack of short
    // KPI cards inherits the height of the tallest possible row and every
    // stat turns into a full-screen monster on a phone.
    private string RootClasses => Cx.Merge("grid", ColumnsClass, GapClass, "auto-rows-auto lg:auto-rows-fr", Class);

    public enum BentoGap { Sm, Md, Lg }
}

@namespace Lumeo

<div class="@RootClasses" @attributes="AdditionalAttributes">
    @if (HeaderContent is not null || !string.IsNullOrEmpty(Title) || !string.IsNullOrEmpty(Description))
    {
        <div class="mb-3 flex flex-col gap-1">
            @if (HeaderContent is not null)
            {
                @HeaderContent
            }
            else
            {
                @if (!string.IsNullOrEmpty(Title))
                {
                    <div class="text-sm font-medium text-foreground">@Title</div>
                }
                @if (!string.IsNullOrEmpty(Description))
                {
                    <div class="text-xs text-muted-foreground">@Description</div>
                }
            }
        </div>
    }

    @if (ChildContent is not null)
    {
        <div class="flex-1 min-h-0">
            @ChildContent
        </div>
    }

    @if (FooterContent is not null)
    {
        <div class="mt-3 pt-3 border-t border-border/60">
            @FooterContent
        </div>
    }
</div>

@code {
    /// <summary>Number of grid columns the tile spans at the <c>lg:</c> breakpoint (1–6); narrower breakpoints widen automatically for tiles wider than 1. Default <c>1</c>.</summary>
    [Parameter] public int Span { get; set; } = 1;

    /// <summary>Number of grid rows the tile spans at the <c>lg:</c> breakpoint (1–4); stays single-row on mobile so content height drives layout. Default <c>1</c>.</summary>
    [Parameter] public int RowSpan { get; set; } = 1;

    /// <summary>The tile's heading text, shown above <see cref="Description"/> when <see cref="HeaderContent"/> isn't supplied.</summary>
    [Parameter] public string? Title { get; set; }

    /// <summary>The tile's subheading text, shown below <see cref="Title"/> when <see cref="HeaderContent"/> isn't supplied.</summary>
    [Parameter] public string? Description { get; set; }

    /// <summary>Custom header content, replacing the default <see cref="Title"/>/<see cref="Description"/> rendering.</summary>
    [Parameter] public RenderFragment? HeaderContent { get; set; }

    /// <summary>The tile's main body content.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Content rendered below a top border at the bottom of the tile.</summary>
    [Parameter] public RenderFragment? FooterContent { get; set; }

    /// <summary>Additional CSS classes merged onto the tile's root element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes splatted onto the tile's root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClasses => Cx.Merge("flex flex-col min-w-0 min-h-0 rounded-xl border border-border/60 bg-card text-card-foreground p-5", SpanClasses, RowSpanClasses, Class);

    // Span classes are emitted as literal Tailwind strings (not interpolated
    // `col-span-{n}`) so the JIT can see them at scan time. On mobile every
    // tile spans 1 col; from `sm:` (≥ 640 px) we widen tiles meant to be 2+
    // wide so they don't go single-column on tablet; the caller's exact span
    // kicks in at `lg:` (≥ 1024 px). RowSpan stays at 1 on mobile so each
    // tile's natural content height drives layout instead of an enforced
    // double-row that creates huge empty boxes on a phone.
    private string SpanClasses => Span switch
    {
        <= 1 => "col-span-1",
        2 => "col-span-1 sm:col-span-2",
        3 => "col-span-1 sm:col-span-2 lg:col-span-3",
        4 => "col-span-1 sm:col-span-2 lg:col-span-4",
        5 => "col-span-1 sm:col-span-2 lg:col-span-5",
        6 => "col-span-1 sm:col-span-2 lg:col-span-6",
        _ => "col-span-1 sm:col-span-2"
    };

    private string RowSpanClasses => RowSpan switch
    {
        <= 1 => "row-span-1",
        2 => "row-span-1 lg:row-span-2",
        3 => "row-span-1 lg:row-span-3",
        4 => "row-span-1 lg:row-span-4",
        _ => "row-span-1"
    };
}
